// Stub temporaire — à remplacer par la vraie lib QR code (ex: davidshimjs/qrcodejs).
// En attendant, on affiche le code en gros, lisible par scan optique simple.
window.QRCode = function(elId, opts) {
  const el = (typeof elId === 'string') ? document.getElementById(elId) : elId;
  if (!el) return;
  el.innerHTML = '<div style="font-family:monospace;font-size:14px;font-weight:700;padding:24px;text-align:center;border:2px dashed #999;background:#FFF;color:#000;">' +
                 (opts.text || '') + '<br><small style="color:#999;font-size:10px;font-weight:400;">QR code à activer (lib à charger)</small></div>';
};
